package main

import (
	"errors"
	"net/http"
)

// TaskHandler handles HTTP requests for the /tasks resource.
type TaskHandler struct {
	store *Store
}

// NewTaskHandler creates a new TaskHandler with the given Store.
func NewTaskHandler(store *Store) *TaskHandler {
	return &TaskHandler{store: store}
}

// Create decodes a JSON Task from the request body and stores it.
func (h *TaskHandler) Create(w http.ResponseWriter, r *http.Request) {
	var t Task
	if err := decodeJSON(r, &t); err != nil {
		writeError(w, http.StatusBadRequest, "malformed request body")
		return
	}
	if err := t.Validate(); err != nil {
		if errors.Is(err, ErrValidation) {
			writeError(w, http.StatusBadRequest, err.Error())
		} else {
			writeError(w, http.StatusInternalServerError, "internal server error")
		}
		return
	}
	if err := h.store.CreateTask(t); err != nil {
		if errors.Is(err, ErrExists) {
			writeJSON(w, http.StatusConflict, nil)
		} else {
			writeJSON(w, http.StatusInternalServerError, nil)
		}
		return
	}
	writeJSON(w, http.StatusCreated, t)
}

// List returns all tasks as a JSON array, optionally filtered by status.
func (h *TaskHandler) List(w http.ResponseWriter, r *http.Request) {
	limit, offset := parsePage(r)
	tasks := h.store.ListTasks()
	if status := r.URL.Query().Get("status"); status != "" {
		filtered := make([]Task, 0)
		for _, t := range tasks {
			if t.Status == status {
				filtered = append(filtered, t)
			}
		}
		tasks = filtered
	}
	paginated := paginate(tasks, limit, offset)
	writeJSON(w, http.StatusOK, paginated)
}

// Get reads the {id} path value and returns the task as JSON.
func (h *TaskHandler) Get(w http.ResponseWriter, r *http.Request) {
	id := r.PathValue("id")
	t, err := h.store.GetTask(id)
	if err != nil {
		if errors.Is(err, ErrNotFound) {
			writeJSON(w, http.StatusNotFound, nil)
		} else {
			writeJSON(w, http.StatusInternalServerError, nil)
		}
		return
	}
	writeJSON(w, http.StatusOK, t)
}

// Delete removes {id} returning 204, or 404 if absent.
func (h *TaskHandler) Delete(w http.ResponseWriter, r *http.Request) {
	id := r.PathValue("id")
	if err := h.store.DeleteTask(id); err != nil {
		if errors.Is(err, ErrNotFound) {
			writeJSON(w, http.StatusNotFound, nil)
		} else {
			writeJSON(w, http.StatusInternalServerError, nil)
		}
		return
	}
	writeJSON(w, http.StatusNoContent, nil)
}
